'use client';
import { useEffect, useState, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { Plus } from 'lucide-react';
import { useDebounce } from 'use-debounce';
import DeleteConfirmationDialog from '@/components/dialog/DeleteConfirmationDialog';
import { useToast } from '@/hooks/use-toast';
import EditHallDialog from '@/components/dialog/EditHallDialog';
import { useAuth } from '@/context/AuthContext';
import { HallType } from '@/types';
import SearchInput from '@/components/ui/SearchInput';
import Pagination from '@/components/ui/Pagination';
import { Loading } from '@/components/ui/Loading';
import NotFound from '@/components/ui/NotFound';
import HallCard from '@/components/ui/HallCard';
import { AddHallDialog } from '@/components/dialog/AddHallDialog';

const AdminHallsPage = () => {
  const { toast } = useToast();
  const { token } = useAuth();

  const [halls, setHalls] = useState<HallType[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery] = useDebounce(searchQuery, 300);
  const [selectedHall, setSelectedHall] = useState<HallType | null>(null);

  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [isAddDialogOpen, setIsAddDialogOpen] = useState(false);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);

  const [currentPage, setCurrentPage] = useState(1);
  const [hallsPerPage] = useState(6);
  const [totalPages, setTotalPages] = useState(0);
  const [totalItems, setTotalItems] = useState(0);

  const [loading, setLoading] = useState(false);

  // ===== Fetch Halls (supports both paginated and non-paginated responses) =====
  const fetchList = useCallback(async () => {
    setLoading(true);
    try {
      // Build query string (backend may support search, page, perPage)
      const qs = new URLSearchParams();
      qs.set('page', String(currentPage));
      qs.set('perPage', String(hallsPerPage));
      if (debouncedQuery) qs.set('search', debouncedQuery);

      const res = await fetch(`http://localhost:8080/halls?${qs.toString()}`, {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
          ...(token ? { Authorization: `Bearer ${token}` } : {}),
        },
      });

      if (!res.ok) {
        const txt = await res.text();
        throw new Error(txt || 'Failed to fetch halls');
      }

      const data = await res.json();

      // handle multiple possible shapes:
      // 1) { halls: [...], totalItems, totalPages }
      // 2) { data: [...] }
      // 3) [...] array directly
      let items: HallType[] = [];
      if (Array.isArray(data)) {
        items = data;
        setTotalItems(data.length);
        setTotalPages(Math.ceil(data.length / hallsPerPage));
      } else if (Array.isArray(data.halls) || Array.isArray(data.data)) {
        items = data.halls ?? data.data;
        setTotalItems(data.totalItems ?? items.length);
        setTotalPages(
          data.totalPages ?? Math.ceil(items.length / hallsPerPage)
        );
      } else {
        // fallback: try common keys
        items = data.items ?? [];
        setTotalItems(data.totalItems ?? items.length);
        setTotalPages(
          data.totalPages ?? Math.ceil(items.length / hallsPerPage)
        );
      }

      setHalls(items);
    } catch (err: any) {
      toast({
        title: 'Fetch Error',
        description: err?.message || 'Failed to load halls',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  }, [currentPage, debouncedQuery, hallsPerPage, token, toast]);

  useEffect(() => {
    fetchList();
  }, [fetchList]);

  // ===== Handlers for dialogs and CRUD =====
  const openAddDialog = () => setIsAddDialogOpen(true);

  const handleAdd = (newHall: HallType) => {
    // optimistic UI: add at top
    setHalls((prev) => [newHall, ...prev]);
    setIsAddDialogOpen(false);
    toast({
      title: 'Hall added',
      description: `${newHall.name} added successfully.`,
    });
  };

  const openEdit = (hall: HallType) => {
    setSelectedHall(hall);
    setIsEditDialogOpen(true);
  };
  const handleEditSuccess = (updatedHall: HallType) => {
    setHalls((prev) =>
      prev.map((h) => (h._id === updatedHall._id ? updatedHall : h))
    );
    setIsEditDialogOpen(false);
    setSelectedHall(null);
    toast({
      title: 'Hall updated',
      description: `${updatedHall.name} updated.`,
    });
  };

  const openDeleteConfirm = (hall: HallType) => {
    setSelectedHall(hall);
    setIsDeleteDialogOpen(true);
  };

  const handleDeleteConfirm = async () => {
    if (!selectedHall) return;
    setLoading(true);
    try {
      const res = await fetch(
        `http://localhost:8080/halls/${selectedHall._id}`,
        {
          method: 'DELETE',
          headers: {
            'Content-Type': 'application/json',
            ...(token ? { Authorization: `Bearer ${token}` } : {}),
          },
        }
      );
      if (!res.ok) {
        const txt = await res.text();
        throw new Error(txt || 'Delete failed');
      }
      // remove from UI
      setHalls((prev) => prev.filter((h) => h._id !== selectedHall._id));
      toast({
        title: 'Hall deleted',
        description: `${selectedHall.name} was deleted.`,
        className: 'bg-green-500 text-white',
      });
    } catch (err: any) {
      toast({
        title: 'Error',
        description: err?.message || 'Failed to delete',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
      setIsDeleteDialogOpen(false);
      setSelectedHall(null);
    }
  };

  // change page
  const paginate = (pageNumber: number) => {
    setCurrentPage(pageNumber);
    // scroll to top of list for better UX
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // If loading show spinner
  if (loading) return <Loading />;

  return (
    <div className='p-6 space-y-6'>
      <div className='flex justify-between items-center gap-4 flex-wrap'>
        {/* Search Input */}
        <SearchInput
          name='Hall'
          searchQuery={searchQuery}
          setSearchQuery={(v) => {
            setSearchQuery(v);
            setCurrentPage(1);
          }}
          setCurrentPage={() => setCurrentPage(1)}
        />

        <Button
          onClick={openAddDialog}
          className='gap-2 mr-4 bg-gradient-to-r from-purple-700 to-indigo-600 text-white'
        >
          <Plus className='h-4 w-4' /> Add Hall
        </Button>
      </div>

      {/* Grid */}
      <div className='grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-6'>
        {halls.length > 0 ? (
          halls.map((hall) => (
            <HallCard
              key={hall._id}
              hall={hall}
              isAdmin
              onEdit={() => openEdit(hall)}
              onDelete={() => openDeleteConfirm(hall)}
            />
          ))
        ) : (
          <NotFound message='Halls not found' />
        )}
      </div>

      {/* Pagination Controls: show when multiple pages */}
      {(totalPages > 1 || halls.length > hallsPerPage) && (
        <Pagination
          currentPage={currentPage}
          totalPages={
            totalPages || Math.ceil((totalItems || halls.length) / hallsPerPage)
          }
          paginate={paginate}
        />
      )}

      {/* Edit Dialog */}
      <EditHallDialog
        open={isEditDialogOpen}
        onClose={() => {
          setIsEditDialogOpen(false);
          setSelectedHall(null);
        }}
        hall={selectedHall}
        token={token}
        onSuccess={handleEditSuccess}
      />

      {/* Delete Confirm */}
      <DeleteConfirmationDialog
        open={isDeleteDialogOpen}
        onOpenChange={setIsDeleteDialogOpen}
        title='Delete Hall'
        description={`Are you sure you want to delete ${
          selectedHall?.name ?? ''
        }?`}
        onConfirm={handleDeleteConfirm}
      />

      {/* Add Dialog */}
      <AddHallDialog
        open={isAddDialogOpen}
        onClose={() => setIsAddDialogOpen(false)}
        onSubmit={handleAdd}
      />
    </div>
  );
};

export default AdminHallsPage;
