'use client';
import { motion } from 'framer-motion';
import { Building2, MapPin, Users } from 'lucide-react';
import { Card, CardContent } from './Card';
import { Button } from './button';
import { HallType } from '@/types';

interface HallCardProps {
  hall: HallType;
  isAdmin?: boolean;
  onEdit?: (hall: HallType) => void;
  onDelete?: (hall: HallType) => void;
}

const HallCard = ({
  hall,
  isAdmin = false,
  onEdit,
  onDelete,
}: HallCardProps) => {
  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4 }}
      whileHover={{ scale: 1.02 }}
    >
      <Card className='rounded-xl border border-purple-200 shadow-md hover:shadow-purple-400 transition-all duration-300'>
        <CardContent className='p-5 space-y-4'>
          <div className='flex justify-between items-start'>
            <h3 className='text-xl font-semibold text-purple-800 flex items-center gap-2'>
              <Building2
                className='text-purple-500'
                size={18}
              />
              {hall.name}
            </h3>
            <span
              className={`text-xs px-2 py-1 rounded-full ${
                hall.status === 'available'
                  ? 'bg-green-100 text-green-700'
                  : 'bg-red-100 text-red-700'
              }`}
            >
              {hall.status}
            </span>
          </div>
          <div className='flex items-center gap-1'>
            <MapPin className='text-purple-500 w-4 h-4' />
            {hall.location}
          </div>
          <div className='flex items-center gap-1'>
            <Users className='text-purple-500 w-4 h-4' />
            {hall.capacity} Seats
          </div>

          {isAdmin && (
            <>
              <div className='text-xs text-purple-600 mt-6'>
                Created at: {new Date(hall?.createdAt).toLocaleString()} <br />
                Updated at: {new Date(hall?.updatedAt).toLocaleString()}
              </div>
              <div className='flex justify-end gap-3 pt-3'>
                <Button
                  variant='outline'
                  size='sm'
                  onClick={() => onEdit?.(hall)}
                  className='border-purple-300 hover:bg-purple-100 text-purple-700'
                >
                  Edit
                </Button>
                <Button
                  variant='destructive'
                  size='sm'
                  onClick={() => onDelete?.(hall)}
                >
                  Delete
                </Button>
              </div>
            </>
          )}
        </CardContent>
      </Card>
    </motion.div>
  );
};

export default HallCard;
